// Code pour nœud Code n8n - Classement Reddit avec output simplifié

// Récupérer les données d'entrée
const items = $input.all();

// Filtrer uniquement les posts (exclure les commentaires)
const posts = items.filter(item => item.json.dataType === 'post');

// Calculer le score pour chaque post
const postsWithScore = posts.map(item => {
  const post = item.json;

  // Calcul du score : 1 point par upvote + 2 points par commentaire
  const upvoteScore = (post.upVotes || 0) * 1;
  const commentScore = (post.numberOfComments || 0) * 2
    ;
  const totalScore = upvoteScore + commentScore;

  return {
    json: {
      url: post.url,
      title: post.title || "Pas de titre",
      body: post.body || "Pas de contenu",
      score: totalScore,
      // Données détaillées pour debug (optionnel)
      details: {
        upvotes: post.upVotes || 0,
        comments: post.numberOfComments || 0,
        community: post.communityName,
        timestamp: post.createdAt
      }
    }
  };
});

// Trier par score décroissant
const sortedPosts = postsWithScore.sort((a, b) => b.json.score - a.json.score);

// Prendre les 10 meilleurs
const top10Posts = sortedPosts.slice(0, 10);

// Ajouter un rang à chaque post
const rankedPosts = top10Posts.map((post, index) => ({
  json: {
    rank: index + 1,
    url: post.json.url,
    title: post.json.title,
    body: post.json.body,
    score: post.json.score
  }
}));

// Log pour debug
console.log(`🏆 TOP 10 POSTS REDDIT - Score = (upvotes×1) + (commentaires×2)`);
console.log(`────────────────────────────────────────────────────────────`);

rankedPosts.forEach((post, index) => {
  const p = post.json;
  const shortTitle = p.title.length > 60 ? p.title.substring(0, 60) + '...' : p.title;
  const shortBody = p.body.length > 80 ? p.body.substring(0, 80) + '...' : p.body;

  console.log(`${p.rank}. Score: ${p.score}`);
  console.log(`   URL: ${p.url}`);
  console.log(`   Titre: "${shortTitle}"`);
  console.log(`   Contenu: "${shortBody}"`);
  console.log(`   ────────────────────────────────────────────────────────`);
});

console.log(`\n📊 Analysé ${posts.length} posts au total`);

// Retourner les résultats avec le format demandé
return rankedPosts;

